  "company.meta.ogTitle": "Nexa — Who we are",
  "company.meta.ogDescription": "A small team of engineers and operators building the system that cheese and dairy logistics needed.",
  "company.meta.title": "Nexa — Who we are",
  "company.hero.badge": "About Nexa",
  "company.hero.title": "We build SaaS software for teams<br>that sell and dispatch refrigerated food.",
  "company.hero.copy": "Nexa is our multi-tenant B2B platform: buyer portal, sales, catalog, inventory, dispatch, documents, and analytics without turning the operation into a generic ecommerce.",
  "company.hero.sidecardAria": "Why operators work with Nexa",
  "company.hero.kicker": "Operational partner",
  "company.hero.sidecardTitle": "We deploy with operators, not just management or procurement.",
