  "company.hero.kpi2": `<div class="hero-kpi-value is-accent">1 day</div><div class="hero-kpi-label">Typical time for a concrete response after first contact.</div>`,
  "company.hero.kpi3": `<div class="hero-kpi-value">30 days</div><div class="hero-kpi-label">Accompaniment period after workspace configuration and phase definition.</div>`,
  "company.hero.kpi4": `<div class="hero-kpi-value">Your team</div><div class="hero-kpi-label">We adapt to the team and the flows your operation already uses.</div>`,
  "company.origin.title": "We built Nexa because nothing existed for<br>the real way charcuterie and dairy operations work.",
  "company.origin.callout": "We spent months inside refrigerated food operations: importers, distributors, and cold storage facilities. The same problems appeared over and over: cheese stock on spreadsheets, charcuterie orders arriving over WhatsApp, and temperature data locked in loggers nobody checked until an audit or a claim.",
  "company.origin.body": "These weren't careless operators. They were serious companies running without software built for their reality. Generic ERPs didn't cover daily execution, CRMs didn't solve stock or dispatch, and logistics apps didn't cover buyer portals. Nexa connects that path from catalog to delivery.",
  "company.origin.stat1": `<div class="gap-stat-number">~40%</div><div class="gap-stat-label">of perishable food in LatAm is lost before reaching the consumer <small>(FAO, regional estimate)</small></div>`,
  "company.origin.stat2": `<div class="gap-stat-number">12%</div><div class="gap-stat-label">average revenue lost to thermal excursions</div>`,
  "company.origin.stat3": `<div class="gap-stat-number gap-stat-number-accent">In progress</div><div class="gap-stat-label">validating results with first operators in production</div>`,
  "company.support.badge": "How we support you",
  "company.support.title": "What happens after you say yes.",
  "company.support.copy": "We don't give you access and disappear. Here's what working with us actually means.",
  "company.support.card1": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M15 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="m16 11 2 2 4-4"></path></svg></div><h3>A real person guides the review</h3><p>Not a video guide or a knowledge base. Someone from our team maps your operation, loads product catalog data, and separates future integrations.</p>`,
  "company.support.card2": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 15v-3a8 8 0 0 1 16 0v3"></path><path d="M18 19a2 2 0 0 0 2-2v-2h-4v4z"></path><path d="M6 19a2 2 0 0 1-2-2v-2h4v4z"></path><path d="M10 19h4"></path></svg></div><h3>You talk to people, not tickets</h3><p>When something breaks or needs adjustment, you reach our team directly. No bot, no ticket queue, no waiting days for a useful answer.</p>`,
  "company.support.card3": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect><line x1="16" y1="2" x2="16" y2="6"></line><line x1="8" y1="2" x2="8" y2="6"></line><line x1="3" y1="10" x2="21" y2="10"></line><path d="M8 15h4"></path><path d="M8 18h8"></path></svg></div><h3>We stay 30 days after workspace configuration</h3><p>We support flow review, adjust product catalog data, and make later-phase integrations explicit.</p>`,
  "company.support.card4": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg></div><h3>Your data stays yours</h3><p>Your inventory, routes, customers, and temperature logs belong to your operation. We never sell or share your information. You can export everything at any time.</p>`,
  "company.support.card5": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="4" y="4" width="16" height="16" rx="2" ry="2"></rect><rect x="9" y="9" width="6" height="6"></rect><line x1="9" y1="1" x2="9" y2="4"></line><line x1="15" y1="1" x2="15" y2="4"></line><line x1="9" y1="20" x2="9" y2="23"></line><line x1="15" y1="20" x2="15" y2="23"></line></svg></div><h3>Ready for your current equipment</h3><p>We do not promise active hardware in alcance inicial. If you already have sensors, we validate compatibility as part of the roadmap.</p>`,
  "company.support.card6": `<div class="company-support-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M8.5 16.5a5 5 0 0 1 7 0"></path><path d="M5 13a10 10 0 0 1 14 0"></path><path d="M2 9.5a15 15 0 0 1 4.36-3.14"></path><path d="M22 9.5a15 15 0 0 0-4.36-3.14"></path><path d="M12 20h.01"></path><path d="M3 3l18 18"></path></svg></div><h3>Works offline</h3><p>Drivers in low-signal areas? The mobile interface models delivery evidence. Temperature, GPS, and automatic sync stay on the roadmap.</p>`,
  "company.thesis.badge": "Built by operators",
  "company.thesis.title": "We build software because we lived the problem.",
  "company.thesis.body1": "Nexa was born in Lima, Peru, with a team of engineers and supply chain operators. We saw first-hand the operational leakage that appears when cheese, charcuterie, and dairy distribution depends on disconnected logs, generic ERPs, and fragmented WhatsApp.",
  "company.thesis.body2": "We don't sell visionary promises. We deploy hard operational fixes. When you work with us, the team that converts your physical flow into reliable digital infrastructure works with you directly.",
  "company.thesis.cta": "Register workspace",
  "company.contact.badge": "Contact",
  "company.contact.title": "Tell us about your operation.",
  "company.contact.copy": "Whether you manage 3 trucks or 30 cold rooms, we'll respond with concrete details on how Nexa applies to your operation. No sales scripts.",
  "company.contact.stepsTitle": "What happens after you write",
  "company.contact.step1": "A real person reads your message, usually within a few hours.",
  "company.contact.step2": "We respond with specific questions about your operation and propose a short call.",
  "company.contact.step3": "On the call, we show you Nexa with your cheeses, charcuterie SKUs, dairy lines, and routes — not a generic presentation.",
  "company.contact.location": "Lima, Peru — serving LatAm",
  "company.contact.form.heading": "Send us a direct message",
  "company.contact.form.nameLabel": "Your name",
  "company.contact.form.namePlaceholder": "Your name",
  "company.contact.form.emailLabel": "Work email",
  "company.contact.form.emailPlaceholder": "Work email",
  "company.contact.form.companyLabel": "Company",
  "company.contact.form.companyPlaceholder": "Company name",
  "company.contact.form.messageLabel": "Operation details",
  "company.contact.form.messagePlaceholder": "What does your operation look like? Cheeses, charcuterie, dairy lines, locations — any detail helps.",
  "company.contact.form.submit": "Register workspace",
  "company.contact.success.title": "Your email application was opened.",
  "company.contact.success.copy": `Review and send the email from your application. This academic site does not store or submit the form to a CRM or form service.`,
  "company.contact.success.note": "In the meantime",
