  "solutions.advantage.card1": `<div class="advantage-icon" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline></svg></div><h3>Operational workspace in days</h3><p>The academic environment shows inventory and orders with evaluation data. Real integrations are planned by phase.</p>`,
